fun solve(s: String, order: Array<Long>, k: Long): Long {
    val n = s.length.toLong()
    if (k == 0L) {
        return 0
    }
    val totalSubstrings = n * (n + 1) / 2
    if (k > totalSubstrings) {
        return -1
    }

    val marked = BooleanArray(n.toInt())
    var currentActive = 0L

    for (t in order.indices) {
        val idx = order[t].toInt()
        if (marked[idx]) {
            continue
        }
        marked[idx] = true
        var left = idx
        while (left >= 0 && !marked[left]) {
            left--
        }
        left++
        var right = idx
        while (right < n.toInt() && !marked[right]) {
            right++
        }
        right--

        val delta = (idx - left + 1).toLong() * (right - idx + 1).toLong()
        currentActive += delta
        if (currentActive >= k) {
            return (t + 1).toLong()
        }
    }
    return -1
}
